#!/usr/bin/env python3
"""Unit tests for CodeRabbit parser."""

import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).resolve().parent))

from parse_coderabbit import (  # noqa: E402
    ChangeImpactLevel,
    merge_signals,
    scenarios_from_recommendation,
)


FIXTURE_HIGH = """
## Change Impact: 🔴 High

**Regression Risk:** High likelihood of behavioral regressions because this change adds ABAC-driven join enforcement.

**QA Recommendation:** Run targeted manual smoke tests for: joining private ABAC teams (allowed vs blocked), public "Recommended" tagging, invite/add-to-team candidate filtering, and system-console sync job behavior (including mass-removal warnings). If E2E runs clean, additional manual QA can be minimal.

*Generated by CodeRabbitAI*
"""

FIXTURE_LOW = """
## Change Impact: 🟢 Low

**Regression Risk:** Test-only changes with no production code modified.

**QA Recommendation:** No manual QA required; existing automated tests were exercised extensively and are sufficient.

*Generated by CodeRabbitAI*
"""

FIXTURE_MEDIUM = """
## Change Impact: 🟡 Medium

**Regression Risk:** Shared post display logic could impact rendering.

**QA Recommendation:** Manual QA should verify consecutive message display behavior focusing on: (1) All consecutive AI messages display headers and badges correctly, (2) Consecutive non-AI messages continue to collapse as expected.

*Generated by CodeRabbitAI*
"""


def test_high_impact():
    signals = merge_signals(FIXTURE_HIGH)
    assert signals.change_impact == ChangeImpactLevel.HIGH
    assert len(signals.parsed_scenarios) >= 1
    assert not signals.suggests_no_manual_qa


def test_low_skip():
    signals = merge_signals(FIXTURE_LOW)
    assert signals.change_impact == ChangeImpactLevel.LOW
    assert signals.suggests_no_manual_qa
    assert signals.should_skip(tpa_status="success")


def test_medium_scenarios():
    signals = merge_signals(FIXTURE_MEDIUM)
    assert signals.change_impact == ChangeImpactLevel.MEDIUM
    assert len(signals.parsed_scenarios) >= 1
    assert not signals.should_skip()


def test_walkthrough_effort():
    walkthrough = "## Estimated code review effort\n\n🎯 5 (Critical) | ⏱️ ~100 minutes\n"
    signals = merge_signals("", walkthrough)
    assert signals.review_effort_score == 5
    assert signals.change_impact == ChangeImpactLevel.HIGH


def test_scenarios_from_recommendation():
    text = "Run targeted manual smoke tests for: joining private ABAC teams (allowed vs blocked), public Recommended tagging"
    scenarios = scenarios_from_recommendation(text)
    assert len(scenarios) >= 2


if __name__ == "__main__":
    test_high_impact()
    test_low_skip()
    test_medium_scenarios()
    test_walkthrough_effort()
    test_scenarios_from_recommendation()
    print("All tests passed")
